import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { EventItem } from '../../core/models';

/**
 * GatherUp public events browse. Search (`?q=`) and category (`?category=`) are
 * bound to the URL query params and restored on load, so deep links like
 * `/#/events?category=Music` reopen the filtered view.
 * Loads the catalog live via ApiService.listEvents(); filtering stays client-side.
 */
@Component({
  selector: 'app-events-list',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './events-list.component.html',
  styleUrl: './events-list.component.css',
})
export class EventsListComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly q = signal('');
  readonly category = signal('');

  readonly allEvents = signal<EventItem[]>([]);

  readonly categories = computed<string[]>(() =>
    [...new Set(this.allEvents().map((e) => e.category))].sort(),
  );

  readonly filtered = computed<EventItem[]>(() => {
    const q = this.q().trim().toLowerCase();
    const cat = this.category();
    return this.allEvents().filter((e) => {
      const matchesQ =
        !q || e.title.toLowerCase().includes(q) || e.description.toLowerCase().includes(q);
      const matchesCat = !cat || e.category === cat;
      return matchesQ && matchesCat;
    });
  });

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private api: ApiService,
  ) {}

  ngOnInit(): void {
    // Restore filters from the URL on load.
    const params = this.route.snapshot.queryParamMap;
    this.q.set(params.get('q') ?? '');
    this.category.set(params.get('category') ?? '');
    // Load the full catalog once; search/category filtering stays client-side
    // (via the `filtered` computed) so the category dropdown and deep-linked
    // URL filters behave identically to the approved mockup.
    this.loading.set(true);
    this.error.set(null);
    this.api.listEvents().subscribe({
      next: (events) => {
        this.allEvents.set(events);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load events. Please try again.');
        this.loading.set(false);
      },
    });
  }

  onSearch(value: string): void {
    this.q.set(value);
    this.syncUrl();
  }

  onCategory(value: string): void {
    this.category.set(value);
    this.syncUrl();
  }

  private syncUrl(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: {
        q: this.q() || null,
        category: this.category() || null,
      },
      queryParamsHandling: 'merge',
    });
  }

  spotsLeft(ev: EventItem): number {
    return Math.max(0, ev.capacity - (ev.confirmedCount ?? 0));
  }

  dateLabel(iso: string): string {
    return new Date(iso).toLocaleDateString(undefined, {
      weekday: 'short', month: 'short', day: 'numeric',
    });
  }
}
